import{_ as l,c as a,o as i,ag as t}from"./chunks/framework.DPDPlp3K.js";const h=JSON.parse('{"title":"VMD","description":"","frontmatter":{},"headers":[],"relativePath":"分子模拟/必备技能/VMD.md","filePath":"分子模拟/必备技能/VMD.md","lastUpdated":null}'),r={name:"分子模拟/必备技能/VMD.md"};function o(n,e,d,c,s,u){return i(),a("div",null,e[0]||(e[0]=[t('<h1 id="vmd" tabindex="-1">VMD <a class="header-anchor" href="#vmd" aria-label="Permalink to &quot;VMD&quot;">​</a></h1><ul><li>VMD（Visual Molecular Dynamics）是一款由美国伊利诺伊大学厄巴纳-香槟分校的理论和计算生物物理学小组开发的开源分子可视化软件。</li><li>可用于蛋白、核酸、脂质双层组装体等生物系统的建模、可视化和分析</li><li>#免费 #开源 #windows #linux</li><li>下载：<a href="https://www.ks.uiuc.edu/Research/vmd/" target="_blank" rel="noreferrer">VMD - Visual Molecular Dynamics</a>, 注册登录即可下载</li><li>教程：<a href="https://www.ks.uiuc.edu/Research/vmd/current/ug/" target="_blank" rel="noreferrer">VMD User&#39;s Guide</a></li><li>VMD支持使用CUDA的GPU加速，静电(即“volmap coulomb”和“volmap coulombmsm”)，隐式配体采样(即“volmap ils”)，径向分布函数的计算，混合拟合方法的拟合质量相互关联计算，轨迹聚类分析，以及分子轨道的计算和渲染</li><li>最新版本的VMD还采用了基于NVIDIA OptiX和CUDA的gpu加速批处理和交互式版本的Tachyon光线追踪引擎</li><li>VMD有两种主要的操作模式，一种是典型的全功能图形启用模式，另一种是纯基于文本的操作模式。全功能图形启用模式需要一个支持OpenGL的图形加速器和最新的驱动程序。</li></ul><h2 id="基本显示" tabindex="-1">基本显示 <a class="header-anchor" href="#基本显示" aria-label="Permalink to &quot;基本显示&quot;">​</a></h2><ul><li>启动VMD会打开三个窗口 <ul><li>显示窗口</li><li>主窗口: 用于点击调整图像的显示</li><li>命令行窗口: 执行一些指令操作(如果是Linux命令行窗口启动, 那么原来的Linux命令行窗口即为VMD的命令行窗口)</li></ul></li><li>显示窗口有三种基本的鼠标模式:旋转、平移、缩放(rotation, translation, and scaling)，对应键盘上的r、t或s键</li><li>更改显示模式：<code>Graphic &gt; Representation</code></li><li>在Selected Atoms文本输入区, 可以通过原子名称、残留物名称或其他标识符来选择，且可以处理正则表达式，还可以根据坐标、原子质量等来选择. <ul><li><code>resname xxx</code> 表示选择xxx残基，名字对应pdb文件中的ATOM字段第四例</li><li><code>atom C</code> 表示选择原子</li><li><code>name C CA N O</code> 表示选择元素</li><li><code>Creat Rep</code> 表示新建一个显示图层</li><li>可以选择对不同的结构、不同的分子展示不同的模型</li></ul></li></ul><h2 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h2><ul><li>输出图像/渲染： <code>File &gt; Render &gt; Render the current scene using:</code><ul><li>Tachyon 选择渲染器</li><li>Start Rendering 按开始渲染按钮。经过一些处理后，应该在命令行中看到：Info) Rendering complete.</li></ul></li><li>如果一切正常，您将在当前工作目录中得到一个名为plot.dat.tga(在MacOS X或Unix上)或plot.dat.bmp(在Windows上)的图像文件。</li><li>使用VMD的tachyon_WIN32程序将渲染得到的.dat文件转换为高清bmp图片： <code>tachyon_WIN32.exe xxx.dat -aasamples 24 -mediumshade -trans_vmd -res 1920 1080 -format BMP -o xxx.bmp</code></li></ul><h2 id="查看动画" tabindex="-1">查看动画 <a class="header-anchor" href="#查看动画" aria-label="Permalink to &quot;查看动画&quot;">​</a></h2><ul><li>轨迹动画：需要轨迹文件及其对应的结构文件</li><li>在主VMD窗口底部有动画控件</li></ul><h2 id="状态保存" tabindex="-1">状态保存 <a class="header-anchor" href="#状态保存" aria-label="Permalink to &quot;状态保存&quot;">​</a></h2><ul><li>可以保存当前工作为.vmd文件, 存当前调整调整的所有设置 <code>File &gt; save visualisation state</code></li><li>或者控制台中，键入命令<code>save state filename</code>，其中filename是要保存工作的文件的名称。后缀.vmd</li><li>打开工作： <code>File &gt; load visualisation state</code></li><li>或者在命令行中，使用命令 <code>VMD -e filename</code> 启动VMD，其中filename是之前保存的文件的名称。</li><li>或者启动VMD后，从文本控制台中输入 <code>play filename</code></li></ul><h2 id="拓展阅读" tabindex="-1">拓展阅读 <a class="header-anchor" href="#拓展阅读" aria-label="Permalink to &quot;拓展阅读&quot;">​</a></h2><ul><li><a href="https://blog.csdn.net/weixin_46483785/article/details/134017419" target="_blank" rel="noreferrer">2023 10月Vmd 下载安装教程，Windows&amp;Linux_vmd-CSDN博客</a></li><li><a href="https://zhuanlan.zhihu.com/p/101565900" target="_blank" rel="noreferrer">VMD(Visual Molecular Dynamics)教程（1） - 知乎</a></li><li><a href="http://vmd.chenzhaoqiang.com/intro/startManual.html" target="_blank" rel="noreferrer">入门教程 — VMD中文教程 2024.09 文档</a></li><li><a href="https://blog.csdn.net/yin1331102028yin/article/details/128827601" target="_blank" rel="noreferrer">pymol&amp;vmd相关_vmd和pymol对比-CSDN博客</a></li></ul>',12)]))}const p=l(r,[["render",o]]);export{h as __pageData,p as default};
